// Several edge cases are unhandled. Make inventory.test.js pass.
export function createInventory() {
  const items = new Map();
  return {
    addItem(name, qty) {
      items.set(name, (items.get(name) || 0) + qty);
    },
    removeItem(name, qty) {
      items.set(name, (items.get(name) || 0) - qty);
    },
    getQty(name) {
      return items.get(name) || 0;
    }
  };
}

import assert from 'node:assert/strict';
import { test } from 'node:test';
import { createInventory } from './src/inventory.js';

test('addItem accumulates quantity', () => {
  const inv = createInventory();
  inv.addItem('apple', 2);
  inv.addItem('apple', 3);
  assert.equal(inv.getQty('apple'), 5);
});

test('removeItem reduces quantity', () => {
  const inv = createInventory();
  inv.addItem('apple', 5);
  inv.removeItem('apple', 2);
  assert.equal(inv.getQty('apple'), 3);
});

test('addItem rejects non-positive quantity', () => {
  const inv = createInventory();
  assert.throws(() => inv.addItem('apple', 0));
  assert.throws(() => inv.addItem('apple', -1));
});

test('removeItem throws when removing more than in stock', () => {
  const inv = createInventory();
  inv.addItem('apple', 2);
  assert.throws(() => inv.removeItem('apple', 5));
});

test('removeItem throws for an unknown item', () => {
  const inv = createInventory();
  assert.throws(() => inv.removeItem('banana', 1));
});
